const result = $input.first().json;
if (!result.result || result.result.length === 0) return null;
const update = result.result[0];
const msg = update.message;
if (!msg || !msg.text) return null;
return {json: {text: msg.text, chatId: msg.chat.id, messageId: msg.message_id, updateId: update.update_id}};

const text = $input.first().json.text || '';
const cmd = text.split(' ')[0].toLowerCase();

let command = '';
switch(cmd) {
  case '/status': command = 'node scripts/telegram/bot.js --cmd=status'; break;
  case '/niches': command = 'node scripts/telegram/bot.js --cmd=niches'; break;
  case '/parse': command = 'node scripts/parser/index.js'; break;
  case '/filter': command = 'node scripts/filter/index.js'; break;
  case '/run': command = 'node scripts/audit/index.js --batch=15'; break;
  case '/pause': command = 'node scripts/telegram/bot.js --cmd=pause'; break;
  case '/resume': command = 'node scripts/telegram/bot.js --cmd=resume'; break;
  case '/history': command = 'node scripts/telegram/bot.js --cmd=history'; break;
  case '/logs': command = 'node scripts/telegram/bot.js --cmd=logs'; break;
  case '/calls': command = 'node scripts/telegram/bot.js --cmd=calls'; break;
  default: return {json: {text: '❓ Unknown command: ' + cmd, chatId: $node['Extract Message'].json.chatId, command: ''}};
}

return {json: {text: $input.first().json.text, chatId: $input.first().json.chatId, messageId: $input.first().json.messageId, command: command}};

let text = '';
const input = $input.first().json;
if (input.message) {
  text = input.message;
} else if (input.error) {
  text = '❌ Error: ' + input.error;
} else if (input.raw) {
  text = input.raw;
} else if (typeof input === 'string') {
  text = input;
} else {
  text = JSON.stringify(input, null, 2);
}
return {json: {text: text || 'Command executed', chatId: $node['Extract Message'].json.chatId}};
